<script setup lang="ts">
import { Head, Link } from '@inertiajs/vue3';
import { ArrowRight, Bookmark, BriefcaseBusiness, CalendarDays, Eye, Heart, MapPin, Play, Sparkles, Trophy, Users } from '@lucide/vue';
import { onMounted, ref } from 'vue';
import AppShell from '../../Layouts/AppShell.vue';
const data=ref<any>({profiles:[],videos:[],opportunities:[],sports:[]}),stats=ref<any>({}),loading=ref(true),sportId=ref(''),error=ref('');const csrf=()=>document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content??'';const compact=(value:number)=>new Intl.NumberFormat('en',{notation:'compact',maximumFractionDigits:1}).format(value??0);const days=(value:string)=>Math.max(0,Math.ceil((+new Date(value)-Date.now())/86400000));
const load=async()=>{loading.value=true;error.value='';try{const response=await fetch('/api/v1/women-in-sports'+(sportId.value?`?sport_id=${sportId.value}`:''),{credentials:'same-origin',headers:{Accept:'application/json'}});const payload=await response.json();if(!response.ok)throw new Error(payload.message);data.value=payload.data;stats.value=payload.stats}catch(exception:any){error.value=exception.message}finally{loading.value=false}};
const save=async(profile:any)=>{const response=await fetch(`/api/v1/saved-profiles/${profile.id}`,{method:profile.saved?'DELETE':'POST',credentials:'same-origin',headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf()},body:'{}'});if(response.ok)profile.saved=!profile.saved};onMounted(load);
</script>
<template><Head title="Women in Sports"/><AppShell><main class="women-hub"><section class="women-hero"><div><span><Sparkles/> WOMEN IN SPORTS</span><h1>Her game. Her story.<br/><em>Her future.</em></h1><p>Discover women athletes, coaches, officials, sporting stories, and opportunities shaping South African sport.</p><div><a href="#talent">Discover talent <ArrowRight/></a><a href="#opportunities">View opportunities</a></div></div><aside><Trophy/><strong>{{stats.profiles||0}}</strong><span>featured women in sport</span></aside></section><section class="women-stats"><article><Users/><strong>{{stats.profiles||0}}</strong><span>Profiles</span></article><article><Play/><strong>{{stats.videos||0}}</strong><span>Stories & highlights</span></article><article><BriefcaseBusiness/><strong>{{stats.opportunities||0}}</strong><span>Open opportunities</span></article></section><nav class="women-sports"><button :class="{active:!sportId}" @click="sportId='';load()">All sports</button><button v-for="sport in data.sports" :class="{active:String(sportId)===String(sport.id)}" @click="sportId=String(sport.id);load()">{{sport.name}} <small>{{sport.athlete_profiles_count}}</small></button></nav><p v-if="error" class="edit-message error">{{error}}</p><p v-if="loading" class="women-empty">Loading Women in Sports…</p><template v-else><section id="talent" class="women-section"><header><div><span>DISCOVER</span><h2>Women to watch</h2></div><Link href="/explore">Advanced talent search <ArrowRight/></Link></header><div v-if="data.profiles.length" class="women-profile-grid"><article v-for="profile in data.profiles"><div class="women-avatar"><img v-if="profile.images?.profile" :src="profile.images.profile"/><span v-else>{{profile.name.slice(0,2).toUpperCase()}}</span></div><div><Link :href="`/@${profile.slug}`">{{profile.name}}</Link><strong>{{[profile.athlete?.sport?.name,profile.athlete?.position?.name].filter(Boolean).join(' · ')||profile.professional?.professional_type||profile.roles?.[0]}}</strong><small><MapPin/>{{[profile.location?.city,profile.location?.province].filter(Boolean).join(', ')||'South Africa'}}</small><p>{{profile.bio||'Building her story in sport.'}}</p></div><button :class="{saved:profile.saved}" @click="save(profile)"><Bookmark :fill="profile.saved?'currentColor':'none'"/>{{profile.saved?'Saved':'Save'}}</button></article></div><p v-else class="women-empty">No matching profiles for this sport yet.</p></section><section class="women-section women-stories"><header><div><span>WATCH</span><h2>Stories & highlights</h2></div></header><div v-if="data.videos.length"><a v-for="video in data.videos" :href="`/feed#${video.id}`"><div><img v-if="video.thumbnail" :src="video.thumbnail"/><video v-else-if="video.stream" :src="video.stream" muted preload="metadata"/><Play fill="white"/></div><strong>{{video.caption||'Sporting highlight'}}</strong><span>{{video.creator.name}} · {{video.sport}}</span><small><Eye/>{{compact(video.views)}} <Heart/>{{compact(video.likes)}}</small></a></div><p v-else class="women-empty">Published highlights will appear here.</p></section><section id="opportunities" class="women-section"><header><div><span>OPPORTUNITIES</span><h2>Open doors</h2></div><Link href="/opportunities">Browse all <ArrowRight/></Link></header><div v-if="data.opportunities.length" class="women-opportunity-grid"><article v-for="item in data.opportunities"><span>{{item.type.replaceAll('_',' ')}}</span><h3>{{item.title}}</h3><strong>{{item.poster}}</strong><p>{{item.description}}</p><footer><small><MapPin/>{{item.is_remote?'Remote':item.city||'South Africa'}}</small><small v-if="item.deadline"><CalendarDays/>{{days(item.deadline)}} days left</small></footer><Link href="/opportunities">View & apply <ArrowRight/></Link></article></div><p v-else class="women-empty">No women-focused opportunities match this sport right now.</p></section></template></main></AppShell></template>
